<!doctype html>
<html lang="fr">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Tableau</title>
  <style>
    :root {
      --bg: #f3f6fb;
      --card: #ffffff;
      --text: #1f2937;
      --muted: #6b7280;
      --line: #e5e7eb;
      --head: #f8fafc;
      --accent: #2563eb;
      --shadow: 0 10px 30px rgba(2, 6, 23, .08);
      --radius: 14px;
    }

    * { box-sizing: border-box; }

    body {
      margin: 0;
      font-family: Inter, system-ui, -apple-system, "Segoe UI", Roboto, Arial, sans-serif;
      background: radial-gradient(1200px 700px at 20% -10%, #dbeafe 0%, transparent 45%), var(--bg);
      color: var(--text);
      line-height: 1.45;
    }

    .wrap {
      width: min(1100px, 100%);
      margin: 32px auto;
      padding: 0 16px;
    }

    .card {
      background: var(--card);
      border: 1px solid var(--line);
      border-radius: var(--radius);
      box-shadow: var(--shadow);
      overflow: hidden;
    }

    .head {
      padding: 18px 20px;
      border-bottom: 1px solid var(--line);
      display: flex;
      justify-content: space-between;
      align-items: center;
      gap: 12px;
      flex-wrap: wrap;
      background: linear-gradient(180deg, #ffffff 0%, #fbfdff 100%);
    }

    .head h1 {
      margin: 0;
      font-size: 1.05rem;
      letter-spacing: .2px;
    }

    .badge {
      color: var(--accent);
      background: #eff6ff;
      border: 1px solid #dbeafe;
      font-size: .85rem;
      padding: 4px 10px;
      border-radius: 999px;
      white-space: nowrap;
    }

    .table-wrap {
      overflow: auto;
      -webkit-overflow-scrolling: touch;
    }

    table {
      width: 100%;
      border-collapse: separate;
      border-spacing: 0;
      min-width: 680px;
    }

    thead th {
      position: sticky;
      top: 0;
      z-index: 2;
      background: var(--head);
      color: #111827;
      font-weight: 600;
      text-align: left;
      border-bottom: 1px solid var(--line);
      padding: 12px 14px;
    }

    tbody td {
      padding: 12px 14px;
      border-bottom: 1px solid var(--line);
      vertical-align: top;
      color: #111827;
    }

    tbody tr:nth-child(even) td {
      background: #fcfdff;
    }

    tbody tr:hover td {
      background: #f7fbff;
    }

    a {
      color: var(--accent);
      text-decoration: none;
      word-break: break-word;
    }

    a:hover {
      text-decoration: underline;
    }

    .footer {
      padding: 12px 20px;
      color: var(--muted);
      font-size: .9rem;
      background: #fff;
    }

    /* Mobile: table -> cards */
    @media (max-width: 760px) {
      .wrap { margin: 18px auto; }
      .head { padding: 14px 14px; }
      .head h1 { font-size: 1rem; }

      table {
        min-width: 0;
        border-collapse: collapse;
      }

      thead {
        display: none;
      }

      tbody, tr, td {
        display: block;
        width: 100%;
      }

      tbody tr {
        margin: 10px 10px 14px;
        border: 1px solid var(--line);
        border-radius: 12px;
        overflow: hidden;
        background: #fff;
      }

      tbody td {
        border: 0;
        border-bottom: 1px solid #f1f5f9;
        padding: 10px 12px 10px 44%;
        position: relative;
        min-height: 40px;
      }

      tbody td:last-child {
        border-bottom: 0;
      }

      tbody td::before {
        content: attr(data-label);
        position: absolute;
        left: 12px;
        top: 10px;
        width: 38%;
        color: var(--muted);
        font-weight: 600;
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
      }
    }
  </style>
</head>
